// Package terraform_dabs_map provides a precomputed bidirectional mapping between
// DABs resource fields and Terraform resource fields, generated by generate_test.go.
package terraform_dabs_map

// FieldSet is a nested set of field path segments. Each key is a single field name;
// an empty child FieldSet marks a leaf (the full path from root is present in the set).
type FieldSet map[string]FieldSet

// Len returns the number of leaf paths in the set.
func (fs FieldSet) Len() int {
	n := 0
	for _, child := range fs {
		if len(child) == 0 {
			n++
		} else {
			n += child.Len()
		}
	}
	return n
}

// RenameNode represents a TF field at one path level. DABs is the corresponding DABs
// segment name when it differs from TF; Children holds renames for deeper paths.
// Both may be set when the segment itself is renamed and sub-fields are renamed too.
type RenameNode struct {
	NewName  string
	Children RenameTree
}

// RenameTree maps single TF field name segments to their rename nodes.
type RenameTree map[string]RenameNode

// Len returns the total number of renamed paths in the tree.
func (rt RenameTree) Len() int {
	n := 0
	for _, node := range rt {
		if node.NewName != "" {
			n++
		}
		n += node.Children.Len()
	}
	return n
}
